// Aggregate transcripts for GLM-4
const items = $input.all();

if (items.length === 0) {
  return [{ json: { hasData: false, combined: '', rowIds: [], leadIds: [], count: 0 } }];
}

const dateLabel = new Date().toLocaleDateString('ru-RU', { timeZone: 'Europe/Moscow' });
const MAX_CHARS = 50000;
const sections = [];
let totalLen = 0;
let truncated = false;

// Group by lead_id
const byLead = {};
for (const item of items) {
  const { lead_id, lead_name, curators, transcript_text, filename } = item.json;
  if (!lead_id) continue;
  const lid = String(lead_id);
  if (!byLead[lid]) byLead[lid] = { lead_id: lid, lead_name: lead_name || `ФФ-${lid}`, curators: curators || '', calls: [] };
  byLead[lid].calls.push(transcript_text || '');
}

for (const lid of Object.keys(byLead)) {
  const g = byLead[lid];
  const section = `=== LEAD-${lid} (${g.lead_name}) ===\n${g.calls.join('\n---\n')}`;
  if (totalLen + section.length > MAX_CHARS) { truncated = true; break; }
  sections.push(section);
  totalLen += section.length;
}

const combined = sections.join('\n\n') + (truncated ? '\n\n[...обрезано...]' : '');
const rowIds = items.slice(0, sections.length).map(i => i.json.id);
const leadIds = Array.from(new Set(items.map(i => String(i.json.lead_id)).filter(Boolean)));

return [{ json: { hasData: true, dateLabel, combined, rowIds, leadIds, count: sections.length, truncated } }];

// Build per-client summary links
const items = $input.all();
const dateStr = new Date().toISOString().slice(0, 10);
const SERVER = 'http://84.252.100.93';
const DIFY_APP_URL = (process.env.DIFY_CHATBOT_URL || `${SERVER}:8080`);

// Group by lead_id
const byLead = {};
for (const item of items) {
  const { lead_id, source_type, lead_name, curators } = item.json;
  if (!lead_id) continue;
  const lid = String(lead_id);
  if (!byLead[lid]) byLead[lid] = { lead_id: lid, lead_name: lead_name || `ФФ-${lid}`, curators: curators || '', has_call: false, has_chat: false };
  if (source_type === 'call') byLead[lid].has_call = true;
  if (source_type === 'chat') byLead[lid].has_chat = true;
}

// Build links block for Telegram message
const linkLines = [];
for (const lid of Object.keys(byLead)) {
  const g = byLead[lid];
  const links = [];
  if (g.has_call) links.push(`<a href="${SERVER}:8080/summaries/${dateStr}/LEAD-${lid}_call_${dateStr}.md">созвон</a>`);
  if (g.has_chat) links.push(`<a href="${SERVER}:8080/summaries/${dateStr}/LEAD-${lid}_chat_${dateStr}.md">чат</a>`);
  const ragLink = `<a href="${DIFY_APP_URL}">RAG↗</a>`;
  linkLines.push(`  <b>LEAD-${lid}</b> ${g.lead_name}: ${links.join(', ')} | ${ragLink}`);
}

return [{ json: { linkBlock: linkLines.join('\n'), leadCount: linkLines.length, dateStr } }];

const promptRows = $input.all();
const meta = $('Aggregate Transcripts').first().json;

const fallbackPrompt = 'Ты бизнес-аналитик. Сформируй ежедневный дайджест по стенограммам встреч.

ФОРМАТ (строго HTML без Markdown):
1) <b>Резюме дня</b> (3-5 предложений)
2) <b>Ключевые договорённости</b> (буллеты)
3) <b>Action items</b> (буллет, ответственный, срок)
4) <b>Риски/блокеры</b> (или Нет)
5) По каждому LEAD-ID: 1-2 ключевых пункта

Максимум 3000 символов. Используй HTML-теги (<b>, <i>), НЕ Markdown.';

const promptText = promptRows.map(r => r.json?.prompt_text).find(v => typeof v === 'string' && v.trim().length > 0);
const systemPrompt = promptText ? promptText.trim() : fallbackPrompt;

return [{ json: { ...meta, systemPrompt } }];

const meta = $('Aggregate Transcripts').first().json;
const linksData = $('Build Summary Links').first().json;
const resp = $json;

// Support both Anthropic and OpenAI response formats
let rawContent = '';
if (resp.content && Array.isArray(resp.content)) {
  rawContent = resp.content.filter(b => b.type === 'text').map(b => b.text).join('\n').trim();
} else if (resp.choices?.[0]?.message) {
  rawContent = (resp.choices[0].message.content || resp.choices[0].message.reasoning_content || '').trim();
}
const content = rawContent || 'Сводка не получена.';

const dateLabel = meta.dateLabel;
const leadList = (meta.leadIds || []).map(id => `LEAD-${id}`).join(', ') || '—';

// Header
const header = `<b>📊 Дайджест за ${dateLabel}</b>\nВстреч: ${meta.count} | Клиентов: ${(meta.leadIds||[]).length}`;

// Summaries block
const linksBlock = linksData.linkBlock ? `\n\n<b>📂 Саммари и RAG:</b>\n${linksData.linkBlock}` : '';

const digest = `${header}\n\n${content}${linksBlock}`.trim();

return [{ json: { digest, summaryText: content, rowIds: meta.rowIds } }];

const text = $json.digest || '';
const max = 4000;
const chunks = [];
for (let i = 0; i < text.length; i += max) {
  chunks.push(text.slice(i, i + max));
}
return chunks.map((chunk, index) => ({
  json: {
    text: chunks.length > 1 ? `${chunk}\n\n(часть ${index + 1}/${chunks.length})` : chunk,
    part: index + 1,
    total: chunks.length
  }
}));

const meta = $('Build Digest').first().json;
const rowIds = Array.isArray(meta.rowIds) ? meta.rowIds : [];
const summaryText = meta.summaryText || '';
return [{ json: { rowIds, summaryText } }];
